import{_ as o,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const i=JSON.parse('{"title":"护城河","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/护城河.md","filePath":"05_quotes/by-theme/护城河.md"}'),r={name:"05_quotes/by-theme/护城河.md"};function l(q,t,c,p,_,s){return e(),a("div",null,[...t[0]||(t[0]=[u('<h1 id="护城河" tabindex="-1">护城河 <a class="header-anchor" href="#护城河" aria-label="Permalink to &quot;护城河&quot;">​</a></h1><blockquote><p>&quot;我们喜欢拥有经济城堡周围的护城河——我们需要的是持久的竞争优势。&quot;——巴菲特</p></blockquote><p>护城河是巴菲特最核心的竞争优势概念，源自军事防御思想，指企业抵御竞争的持久保护。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;经济城堡周围的护城河，是抵御竞争的持久优势。品牌、成本优势、专利、网络效应……这些都是护城河的形式。&quot;</p></blockquote><blockquote><p>&quot;报纸的商业模式曾经极其强大，是真正的护城河。互联网的崛起把这护城河变成了小溪。&quot;</p></blockquote><blockquote><p>&quot;喜诗糖果的护城河来自品牌力、地理位置和历史积淀。消费者愿意为它支付溢价，这种能力是其他糖果店难以复制的。&quot;</p></blockquote><blockquote><p>&quot;GEICO可持续的成本优势，正是早在1951年就吸引我关注这家公司的原因。整个公司当时估值仅700万美元。&quot;</p></blockquote><blockquote><p>&quot;多元化集团试图通过资本配置来管理旗下企业，但通常效果不佳——因为真正的护城河来自业务本身，不是金融工程。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1977年 · 1993年 · 1996年 · 2006年 · 2009年 · 2019年</p>',13)])])}const h=o(r,[["render",l]]);export{i as __pageData,h as default};
